def distance(a, n):
    min_index = 0
    max_index = 0

    for i in range(1, n):
        if a[i] < a[min_index]:
            min_index = i
        if a[i] > a[max_index]:
            max_index = i

    return max(max_index, n - min_index - 1)


n = int(input())
a = list(map(int, input().split()))

print(distance(a, n))
